final:
module top_module (
    input p,
    input v,
    input r,
    input a,
    output reg no
);
    always @(*) begin
        case ({p, v, r, a})
            4'b1010: no = 1'b1;
            4'b1001: no = 1'b1;
            4'b0110: no = 1'b1;
            4'b1100: no = 1'b0;
            4'b0100: no = 1'b0;
            4'b0000: no = 1'b0;
            4'b1110: no = 1'b0;
            4'b0001: no = 1'b1;
            4'b0011: no = 1'b0;
            4'b1011: no = 1'b0;
            4'b1101: no = 1'b1;
            4'b0101: no = 1'b0;
            4'b1000: no = 1'b1;
            4'b0111: no = 1'b0;
            4'b1111: no = 1'b0;
            4'b0010: no = 1'b0;
        endcase
    end
endmodule
